}

.savings-item.saved {
    border: 2px solid var(--accent-green);
    background: rgba(6, 255, 165, 0.1);
}

.savings-label {
    font-size: 0.85em;
    color: var(--text-secondary);
    margin-bottom: 5px;
}

.savings-amount {
    font-size: 1.8em;
    font-weight: bold;
    margin-bottom: 5px;
}

.savings-item.waste .savings-amount {
    color: var(--accent-red);
}

.savings-item.saved .savings-amount {
    color: var(--accent-green);
}

.savings-desc {
    font-size: 0.75em;
    color: var(--text-secondary);
}

.savings-divider {
    width: 2px;
    height: 60px;
    background: rgba(255, 255, 255, 0.1);
    margin: 0 15px;
}

.net-savings {
    text-align: center;
    padding: 15px;
    background: var(--bg-secondary);
    border-radius: 10px;
    margin-top: 10px;
}

.net-label {
    font-size: 0.85em;
    color: var(--text-secondary);
    margin-bottom: 5px;
}

.net-amount {
    font-size: 2em;
    font-weight: bold;
    color: var(--accent-teal);
    margin-bottom: 5px;
}

.net-percentage {
    font-size: 1em;
    color: var(--accent-green);
    font-weight: 600;
}

.savings-amount, .net-amount, .net-percentage {
    display: block !important;
    visibility: visible !important;
}

#savingsChart {
    display: block !important;
    visibility: visible !important;
    height: 200px !important;
}

.device-savings-list {
    margin-top: 20px;
    max-height: 200px;
    overflow-y: auto;
}

.device-savings-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px;
    margin-bottom: 8px;
    background: rgba(255, 255, 255, 0.03);
    border-radius: 8px;
    border-left: 3px solid transparent;
}

.device-info {
    flex: 1;
}

.device-name {
    font-size: 0.9em;
    color: var(--text-primary);
    font-weight: 600;
    margin-bottom: 3px;
}

.device-power {
    font-size: 0.75em;
    color: var(--text-secondary);
}

.waste-power {
    color: var(--accent-red);
    margin-right: 10px;
}

.saved-power {
    color: var(--accent-green);
}

.device-savings {
    font-size: 0.95em;
    font-weight: bold;
    min-width: 60px;
    text-align: right;
}

.device-savings.positive {
    color: var(--accent-green);
}

.device-savings.negative {
    color: var(--accent-red);
}

.no-devices {
    text-align: center;
    color: var(--text-secondary);
    font-size: 0.85em;
    padding: 20px;
}

/* ==================== TAB PANES ==================== */

.tab-pane {
    display: none !important;
}

.tab-pane.active {
    display: grid !important;
}

.main-content > .tab-pane {
    display: none !important;
}

.main-content > .tab-pane.active {
    display: grid !important;
}

.card.full-width {
    grid-column: 1 / -1;
}

.chart-container.large {
    height: 300px;
}

/* ==================== COST ANALYSIS ==================== */

.cost-analysis {
    padding: 10px 0;
}

.cost-summary {
    display: flex;
    gap: 20px;
    margin-bottom: 30px;
    flex-wrap: wrap;
}

.cost-card {
    display: flex;
    align-items: center;
    gap: 15px;
    padding: 20px 25px;
    background: var(--bg-secondary);
    border-radius: 12px;
    flex: 1;
    min-width: 200px;
}

.cost-icon {
    font-size: 2em;
}

.cost-info {
    display: flex;
    flex-direction: column;
}

.cost-label {
    font-size: 0.85em;
    color: var(--text-secondary);
    margin-bottom: 5px;
}

.cost-value {
    font-size: 1.5em;
    font-weight: bold;
    color: var(--text-primary);
}

.device-cost-list {
    display: flex;
    flex-direction: column;
    gap: 10px;
}

.device-cost-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px;
    background: rgba(255, 255, 255, 0.03);
    border-radius: 8px;
}

.device-cost-item .device-name {
    font-size: 0.95em;
    color: var(--text-primary);
}

.device-cost-value {
    font-size: 1.1em;
    font-weight: bold;
    color: var(--accent-teal);
}

/* ==================== APPLIANCES TAB ==================== */

.appliances-cards {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 20px;
}

.appliance-card {
    background: var(--bg-secondary);
    border-radius: 12px;
    padding: 20px;
    transition: transform 0.3s ease;
}

.appliance-card:hover {
    transform: translateY(-5px);
}

.appliance-card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 15px;
}

.appliance-card-name {
    font-size: 1.1em;
    font-weight: 600;
    color: var(--text-primary);
}

.appliance-card-status {
    font-size: 0.75em;
    padding: 4px 10px;
    border-radius: 12px;
    font-weight: 600;
}

.appliance-card-status.active {
    background: rgba(6, 255, 165, 0.2);
    color: var(--accent-green);
}

.appliance-card-status.inactive {
    background: rgba(255, 255, 255, 0.1);
    color: var(--text-secondary);
}

.appliance-card-power {
    font-size: 1.8em;
    font-weight: bold;
    color: var(--text-primary);
    margin-bottom: 5px;
}

.appliance-card-mode {
    font-size: 0.85em;
    color: var(--text-secondary);
}

.appliance-status-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.status-item {
    display: flex;
    align-items: center;
    gap: 15px;
    padding: 12px 15px;
    background: rgba(255, 255, 255, 0.03);
    border-radius: 8px;
}

.status-indicator {
    width: 12px;
    height: 12px;
    border-radius: 50%;
}

.status-indicator.on {
    background: var(--accent-green);
    box-shadow: 0 0 10px var(--accent-green);
}

.status-indicator.off {
    background: var(--text-secondary);
}

.status-name {
    flex: 1;
    font-size: 0.95em;
    color: var(--text-primary);
}

.status-power {
    font-size: 0.9em;
    color: var(--text-secondary);
}

/* ==================== ROOMS TAB ==================== */

.rooms-summary {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    gap: 20px;
    margin-bottom: 30px;
}

.room-card {
    background: var(--bg-secondary);
    border-radius: 12px;
    padding: 25px 20px;
    text-align: center;
    transition: transform 0.3s ease;
}

.room-card:hover {
    transform: translateY(-5px);
}

.room-icon {
    font-size: 2.5em;
    margin-bottom: 15px;
}

.room-name {
    font-size: 1em;
    font-weight: 600;
    color: var(--text-primary);
    margin-bottom: 10px;
}

.room-usage {
    font-size: 1.3em;
    font-weight: bold;
    color: var(--accent-teal);
}

.room-details-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.room-detail-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px;
    background: rgba(255, 255, 255, 0.03);
    border-radius: 8px;
}

.room-detail-name {
    font-size: 0.95em;
    color: var(--text-primary);
}

.room-detail-usage {
    font-size: 1em;
    font-weight: bold;
    color: var(--accent-teal);
}

/* ==================== RESPONSIVE DESIGN ==================== */

@media (max-width: 1200px) {
    .dashboard-grid {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 900px) {
    .sidebar {
        width: 70px;
        padding: 20px 10px;
    }

    .logo h1,
    .beta-badge,
    .nav-item span:not(.icon) {
        display: none;
    }

    .nav-item {
        justify-content: center;
        padding: 15px;
    }

    .main-content {
        margin-left: 70px;
    }
}

@media (max-width: 600px) {
    .header {
        flex-direction: column;
        gap: 15px;
        align-items: flex-start;
    }

    .cost-comparison {
        flex-direction: column;
        gap: 20px;
    }
}

/* ==================== LIGHT THEME ==================== */

body[data-theme="light"] {
    --bg-primary: #f5f7fa;
    --bg-secondary: #e8ecf1;
    --bg-card: #ffffff;
    --text-primary: #1a2332;
    --text-secondary: #5a6a7a;
    --accent-teal: #20b2aa;
    --accent-yellow: #f0c040;
    --accent-pink: #e85a7d;
    --accent-purple: #9b59b6;
    --accent-green: #2ecc71;
    --accent-red: #e74c3c;
    --border-color: #d0d7de;
}

body[data-theme="light"] .sidebar {
    background: #e8ecf1;
}

body[data-theme="light"] .card {
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.1);
}

body[data-theme="light"] .nav-item.active {
    background: rgba(32, 178, 170, 0.1);
}

body[data-theme="light"] .time-filter {
    background: #ffffff;
}

body[data-theme="light"] .filter-btn.active {
    background: var(--bg-card);
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}

body[data-theme="light"] .theme-toggle {
    background: #ffffff;
}

body[data-theme="light"] .theme-toggle:hover {
    box-shadow: 0 0 15px rgba(32, 178, 170, 0.4);
}

