/* ==================== GLOBAL RESET ==================== */

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

:root {
    /* Color Palette - Dark Theme (Default) */
    --bg-primary: #1a2332;
    --bg-secondary: #243447;
    --bg-card: #2a3f5f;
    --text-primary: #ffffff;
    --text-secondary: #b0c4de;
    --accent-teal: #4ecdc4;
    --accent-yellow: #ffd166;
    --accent-pink: #ff6b9d;
    --accent-purple: #c77dff;
    --accent-green: #06ffa5;
    --accent-red: #ff4757;
    --border-color: #3d5a80;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: var(--bg-primary);
    color: var(--text-primary);
    overflow-x: hidden;
    transition: background 0.5s ease, color 0.5s ease;
}

/* Theme Transition Animations */
.app-container,
.sidebar,
.main-content,
.card,
.nav-item,
.theme-section {
    transition: all 0.5s ease;
}

button,
.filter-btn {
    transition: all 0.3s ease;
}

.chart-container canvas {
    transition: all 0.5s ease;
}

/* ==================== DEVICE CONTROL ==================== */

.device-control {
    padding: 20px;
}

.device-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px;
    background: var(--bg-secondary);
    border-radius: 10px;
    margin-bottom: 10px;
}

.device-info {
    display: flex;
    flex-direction: column;
}

.device-name {
    font-weight: 600;
    color: var(--text-primary);
    margin-bottom: 5px;
}

.device-status {
    font-size: 0.9rem;
    color: var(--text-secondary);
}

.device-status.online {
    color: var(--accent-green);
}

.device-status.offline {
    color: var(--accent-red);
}

/* Toggle Switch */
.switch {
    position: relative;
    display: inline-block;
    width: 60px;
    height: 34px;
}

.switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.slider {
    position: absolute;
    cursor: pointer;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-color: #ccc;
    transition: .4s;
    border-radius: 34px;
}

.slider:before {
    position: absolute;
    content: "";
    height: 26px;
    width: 26px;
    left: 4px;
    bottom: 4px;
    background-color: white;
    transition: .4s;
    border-radius: 50%;
}

input:checked + .slider {
    background-color: var(--accent-teal);
}

input:checked + .slider:before {
    transform: translateX(26px);
}

/* ==================== APPLIANCES TAB STYLES ==================== */

.appliances-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
    gap: 20px;
    padding: 20px;
}

.appliance-card {
    background: var(--bg-secondary);
    border-radius: 10px;
    padding: 20px;
    cursor: pointer;
    transition: all 0.3s ease;
    border: 2px solid transparent;
}

.appliance-card:hover {
    border-color: var(--accent-teal);
    transform: translateY(-2px);
}

.appliance-card.selected {
    border-color: var(--accent-teal);
    background: var(--bg-card);
}

.appliance-card-name {
    font-weight: 600;
    margin-bottom: 10px;
    color: var(--text-primary);
}

.appliance-card-status {
    font-size: 0.9rem;
    color: var(--text-secondary);
    margin-bottom: 5px;
}

.appliance-card-power {
    font-size: 1.2rem;
    font-weight: bold;
    color: var(--accent-teal);
}

/* Device Details */
.device-details {
    padding: 20px;
}

.detail-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 10px 0;
    border-bottom: 1px solid var(--border-color);
}

.detail-item:last-child {
    border-bottom: none;
}

.detail-label {
    font-weight: 500;
    color: var(--text-secondary);
}

.detail-value {
    font-weight: 600;
    color: var(--text-primary);
}

/* Instant Control */
.instant-control {
    padding: 20px;
}

.control-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px;
    background: var(--bg-secondary);
    border-radius: 10px;
    margin-bottom: 10px;
}

.control-label {
    font-weight: 600;
    color: var(--text-primary);
}

.control-buttons {
