    gap: 10px;
}

.control-btn {
    padding: 8px 20px;
    border: none;
    border-radius: 5px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
}

.control-btn.on {
    background: var(--accent-green);
