}

.control-btn.on:hover {
    background: #05d686;
}

.control-btn.off {
    background: var(--accent-red);
    color: white;
}

.control-btn.off:hover {
    background: #ff3838;
}

/* Time Scheduler */
.scheduler {
    padding: 20px;
}

.schedule-form {
    background: var(--bg-secondary);
    padding: 20px;
    border-radius: 10px;
    margin-bottom: 20px;
}

.form-group {
