    margin-bottom: 5px;
    color: var(--text-secondary);
    font-weight: 500;
}

.time-input, .action-select {
    width: 100%;
    padding: 8px 12px;
    background: var(--bg-card);
    border: 1px solid var(--border-color);
    border-radius: 5px;
    color: var(--text-primary);
}

.schedule-btn {
    width: 100%;
    padding: 10px;
    background: var(--accent-teal);
    color: white;
    border: none;
    border-radius: 5px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
}

.schedule-btn:hover {
    background: #3db8af;
}

.schedule-list {
    max-height: 200px;
    overflow-y: auto;
}

.schedule-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 10px;
    background: var(--bg-secondary);
    border-radius: 5px;
    margin-bottom: 10px;
}

.schedule-info {
    flex: 1;
}

.schedule-time {
    font-weight: 600;
    color: var(--text-primary);
}

.schedule-action {
    font-size: 0.9rem;
    color: var(--text-secondary);
}

.schedule-delete {
    padding: 5px 10px;
    background: var(--accent-red);
    color: white;
    border: none;
    border-radius: 3px;
    cursor: pointer;
    font-size: 0.8rem;
}

/* ==================== APP CONTAINER ==================== */

.app-container {
    display: flex;
    min-height: 100vh;
    position: relative;
    z-index: 1;
}

/* ==================== SIDEBAR ==================== */

.sidebar {
    width: 250px;
    background: #1a1f3a;
