/* ==================== THEME TOGGLE ==================== */

.theme-section {
    margin-top: auto;
    padding: 20px 15px;
    border-top: 1px solid var(--border-color);
    display: flex;
    justify-content: center;
}

.theme-toggle {
    width: 50px;
    height: 50px;
    border-radius: 50%;
    border: 2px solid var(--border-color);
    background: var(--bg-secondary);
    cursor: pointer;
    font-size: 1.5em;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.3s ease;
}

.theme-toggle:hover {
    transform: scale(1.1);
    border-color: var(--accent-teal);
    box-shadow: 0 0 15px var(--accent-teal);
}

.theme-icon {
